import{c as e,i as t,n,o as r,r as i,s as a,t as o}from"./app-CsVfPmwr.js";var s=JSON.parse(`{"path":"/products/fidget-toy.html","title":"피젯 토이 (Fidget Toy)","lang":"ko-KR","frontmatter":{"description":"피젯 토이 (Fidget Toy) 피젯 토이(Fidget Toy)는 손으로 만지고 조작하면서 불안이나 무료함을 해소하고 집중력을 유지하는 데 도움을 주는 소형 장난감이다. &quot;피젯(fidget)&quot;은 영어로 &quot;안절부절못하다&quot;, &quot;손발을 가만히 두지 못하다&quot;는 뜻이다....","head":[["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"피젯 토이 (Fidget Toy)\\",\\"image\\":[\\"https://kmbzn.com/images/og.png\\"],\\"dateModified\\":\\"2026-06-12T15:21:05.000Z\\",\\"author\\":[]}"],["meta",{"property":"og:url","content":"https://kmbzn.com/products/fidget-toy.html"}],["meta",{"property":"og:title","content":"피젯 토이 (Fidget Toy)"}],["meta",{"property":"og:description","content":"피젯 토이 (Fidget Toy) 피젯 토이(Fidget Toy)는 손으로 만지고 조작하면서 불안이나 무료함을 해소하고 집중력을 유지하는 데 도움을 주는 소형 장난감이다. &quot;피젯(fidget)&quot;은 영어로 &quot;안절부절못하다&quot;, &quot;손발을 가만히 두지 못하다&quot;는 뜻이다...."}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:image","content":"https://kmbzn.com/images/og.png"}],["meta",{"property":"og:locale","content":"ko-KR"}],["meta",{"property":"og:updated_time","content":"2026-06-12T15:21:05.000Z"}],["meta",{"property":"article:modified_time","content":"2026-06-12T15:21:05.000Z"}]]},"git":{"createdTime":1781277665000,"updatedTime":1781277665000,"contributors":[{"name":"kmbzn","username":"kmbzn","email":"kmbzn24@gmail.com","commits":1,"url":"https://github.com/kmbzn"},{"name":"Claude Sonnet 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"8227255e0018b0d2c63e50076b5cc2406a472c1d","time":1781277665000,"email":"kmbzn24@gmail.com","author":"kmbzn","message":"feat: add SEO plugins, new articles (Baroque/FC/fidget), sidebar updates","coAuthors":[{"name":"Claude Sonnet 4.6","email":"noreply@anthropic.com"}]}]},"filePathRelative":"products/fidget-toy.md","autoDesc":true}`),c={name:`fidget-toy.md`},l={class:`print-section`};function u(o,s,c,u,d,f){let p=e(`DateMeta`);return a(),i(`div`,null,[n(`section`,l,[s[0]||=n(`h1`,{id:`피젯-토이-fidget-toy`,tabindex:`-1`},[n(`a`,{class:`header-anchor`,href:`#피젯-토이-fidget-toy`},[n(`span`,null,`피젯 토이 (Fidget Toy)`)])],-1),r(p),s[1]||=n(`p`,null,`피젯 토이(Fidget Toy)는 손으로 만지고 조작하면서 불안이나 무료함을 해소하고 집중력을 유지하는 데 도움을 주는 소형 장난감이다. "피젯(fidget)"은 영어로 "안절부절못하다", "손발을 가만히 두지 못하다"는 뜻이다. 특히 ADHD, 불안 장애, 자폐 스펙트럼을 가진 사람들의 감각 조절 도구로 주목받았으며, 일반인에게는 스트레스 해소와 습관적 손 놀림(펜 돌리기, 손가락 두드리기 등)을 대체하는 용도로 쓰인다.`,-1),s[2]||=n(`hr`,null,null,-1)]),s[3]||=t(`<section class="print-section"><h2 id="주요-종류" tabindex="-1"><a class="header-anchor" href="#주요-종류"><span>주요 종류</span></a></h2></section><section class="print-section"><h3 id="피젯-스피너-fidget-spinner" tabindex="-1"><a class="header-anchor" href="#피젯-스피너-fidget-spinner"><span>피젯 스피너 (Fidget Spinner)</span></a></h3><p>2017년 전 세계적으로 폭발적인 유행을 일으킨 피젯 토이. 중앙 베어링을 엄지와 중지로 잡고 검지로 튕기면 날개가 수분간 돌아간다.</p><ul><li><strong>구조</strong>: 중앙 베어링(ABEC-7 이상) + 3~5개 날개(또는 2개)</li><li><strong>소재</strong>: ABS 플라스틱 / 황동 / 스테인리스 스틸 / 티타늄</li><li><strong>특징</strong>: 회전 유지 시간(spin time)이 핵심 스펙. 고급 금속 베어링 사용 시 5~10분 이상 유지</li><li><strong>유행</strong>: 2017년 초 SNS에서 바이럴 → 전 세계 판매량 수억 개</li><li><strong>하락</strong>: 2017년 하반기부터 급격히 식었으나 매니아 층은 유지</li></ul><table><thead><tr><th>소재</th><th>특징</th><th>가격대</th></tr></thead><tbody><tr><td>플라스틱</td><td>가벼움, 저렴</td><td>1,000~5,000원</td></tr><tr><td>황동/구리</td><td>묵직한 무게감, 긴 스핀타임</td><td>1~5만원</td></tr><tr><td>티타늄</td><td>경량 + 고강도, 최상급</td><td>5~20만원</td></tr><tr><td>스틸</td><td>균형 잡힌 무게</td><td>2~8만원</td></tr></tbody></table></section><section class="print-section"><h3 id="피젯-큐브-fidget-cube" tabindex="-1"><a class="header-anchor" href="#피젯-큐브-fidget-cube"><span>피젯 큐브 (Fidget Cube)</span></a></h3><p>2016년 Antsy Labs가 킥스타터를 통해 선보인 6면체 피젯 장난감. 각 면에 서로 다른 조작 방식이 있어 다양한 자극을 제공한다.</p><p><strong>6개 면 구성</strong></p><table><thead><tr><th>면</th><th>기능</th></tr></thead><tbody><tr><td>클릭</td><td>5개 버튼 (3개는 클릭감, 2개는 무소음)</td></tr><tr><td>글라이드</td><td>조이스틱 형태의 구슬</td></tr><tr><td>플립</td><td>딸깍거리는 스위치</td></tr><tr><td>브리드</td><td>누르고 있는 홈 (단순 압박감)</td></tr><tr><td>롤</td><td>기어 + 회전볼</td></tr><tr><td>스핀</td><td>회전 다이얼</td></tr></tbody></table><ul><li>원본 Antsy Labs 제품 외 수많은 유사품이 유통됨</li><li>키체인 크기의 미니 버전도 있음</li></ul></section><section class="print-section"><h3 id="팝-잇-pop-it" tabindex="-1"><a class="header-anchor" href="#팝-잇-pop-it"><span>팝 잇 (Pop It)</span></a></h3><p>2020~2021년 코로나 시기에 전 세계적으로 유행한 실리콘 버블 피젯 토이. 뽁뽁이(에어캡) 누르는 감촉을 무한히 재현할 수 있다.</p><ul><li>실리콘 소재의 돌기를 누르면 &quot;딸깍&quot; 소리 + 촉감 → 반대편에서 다시 누르면 원상복구</li><li>다양한 형태(하트, 원, 공룡, 과일 등)와 컬러</li><li>2인 게임 방식 있음 (번갈아 한 번에 원하는 수만큼 누름, 마지막 남은 칸을 누르는 사람이 짐)</li><li>세척 가능, 반영구 사용</li></ul></section><section class="print-section"><h3 id="인피니티-큐브-infinity-cube" tabindex="-1"><a class="header-anchor" href="#인피니티-큐브-infinity-cube"><span>인피니티 큐브 (Infinity Cube)</span></a></h3><p>접히는 마디들이 무한히 변형되는 구조의 피젯 토이. 정육면체 형태에서 시작해 손목 스냅으로 접고 펴는 동작을 반복한다. 단순하지만 손에서 내려놓기 어려운 특성이 있어 회의 중이나 집중 작업 중 무의식적으로 손이 가는 형태다.</p><ul><li>소재: ABS 플라스틱 / 알루미늄</li><li>크기: 2.5~4cm 수준으로 휴대성 좋음</li></ul></section><section class="print-section"><h3 id="마그네틱-링-마그네틱-볼-magnetic-fidget" tabindex="-1"><a class="header-anchor" href="#마그네틱-링-마그네틱-볼-magnetic-fidget"><span>마그네틱 링 / 마그네틱 볼 (Magnetic Fidget)</span></a></h3><p>강력한 네오디뮴 자석으로 만든 피젯 도구들.</p><ul><li><strong>마그네틱 링</strong>: 손가락 사이에서 회전하며 딸깍거림. 고급 버전은 티타늄 또는 스테인리스 스틸</li><li><strong>마그네틱 볼 (M-Ball, Newton&#39;s cradle 계열)</strong>: 두 손에 하나씩 쥐고 서로 가까이 가져가면 자력으로 달라붙고 튕기는 촉감</li><li><strong>주의</strong>: 강력 자석은 어린이가 삼키면 위험. 어른용 명시 제품 권장</li></ul></section><section class="print-section"><h3 id="슬라임-킨에틱-샌드-kinetic-sand" tabindex="-1"><a class="header-anchor" href="#슬라임-킨에틱-샌드-kinetic-sand"><span>슬라임 / 킨에틱 샌드 (Kinetic Sand)</span></a></h3><p>감각 자극 피젯의 일종.</p><ul><li><strong>슬라임</strong>: 폴리비닐알코올(PVA) 풀 + 붕사/콘택트렌즈 세정제 혼합으로 만든 점탄성 소재. 늘리고 찌르는 촉감이 특징</li><li><strong>킨에틱 샌드</strong>: 모래 97% + 실리콘 폴리머 3%. 젖은 모래처럼 뭉치지만 실제로는 건식. 형태 유지와 흘러내림이 공존하는 독특한 촉감</li></ul><hr></section><section class="print-section"><h2 id="효과에-대한-연구" tabindex="-1"><a class="header-anchor" href="#효과에-대한-연구"><span>효과에 대한 연구</span></a></h2><p>피젯 토이의 집중력 향상 효과는 연구 결과가 엇갈린다.</p><p><strong>긍정적 연구</strong></p><ul><li>ADHD 아동에서 운동 자극(fidgeting)이 인지 과제 수행 시 도움이 된다는 연구 있음</li><li>반복적인 손 움직임이 코르티솔(스트레스 호르몬) 감소에 기여한다는 연구 있음</li><li>감각 처리 이상(자폐 스펙트럼 등)에서 자기 조절 도구로 유효하다는 임상 보고</li></ul><p><strong>부정적·중립적 연구</strong></p><ul><li>일반 초등학생 대상 연구에서 피젯 스피너가 수업 집중력을 <strong>저하</strong>시킨다는 결과</li><li>많은 효과 주장이 일화적(anecdotal) 근거에 머무름</li><li>대규모 임상 연구 부족</li></ul><p><strong>현재 컨센서스</strong>: ADHD 진단을 받은 사람, 또는 감각 처리에 어려움이 있는 사람에게는 도움이 될 수 있으나, 일반적인 집중력 향상 도구로서의 효과는 과학적으로 충분히 입증되지 않았다.</p><hr></section><section class="print-section"><h2 id="구매-가이드" tabindex="-1"><a class="header-anchor" href="#구매-가이드"><span>구매 가이드</span></a></h2><table><thead><tr><th>목적</th><th>추천 제품</th></tr></thead><tbody><tr><td>소음 없이 사무실에서</td><td>피젯 큐브 (무소음 버튼 면), 마그네틱 링</td></tr><tr><td>단순 손 자극, 이동 중</td><td>인피니티 큐브, 마그네틱 볼</td></tr><tr><td>아이와 함께</td><td>팝 잇, 킨에틱 샌드</td></tr><tr><td>수집·마니아</td><td>고급 금속 피젯 스피너 (황동/티타늄)</td></tr><tr><td>감각 처리 지원</td><td>슬라임, 킨에틱 샌드, 텍스처 다양한 매시 토이</td></tr></tbody></table><p><strong>구매처</strong></p><ul><li>AliExpress: 가장 저렴, 배송 2~4주</li><li>다이소: 팝 잇, 기본 피젯 스피너 저렴하게 구비</li><li>쿠팡: 다양한 제품, 국내 빠른 배송</li><li>전문 피젯 숍(Fidget HQ 등): 고급 금속 피젯 전문</li></ul></section>`,9)])}var d=o(c,[[`render`,u]]);export{s as _pageData,d as default};